#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <assert.h>
#include <omp.h>

#define BLOCK_SIZE 16
#define STR_SIZE 256
#define EXPAND_RATE 2

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

#define MIN(a, b) ((a)<=(b) ? (a) : (b))

const static float t_chip = 0.0005;
const static float chip_height = 0.016;
const static float chip_width = 0.016;
const static float amb_temp = 80.0f;

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))

void writeoutput(float *vect, int grid_rows, int grid_cols, char *file) {
	int i,j, index=0;
	FILE *fp;
	char str[STR_SIZE];

	if( (fp = fopen(file, "w" )) == 0 )
          printf( "The file was not opened\n" );

	for (i=0; i < grid_rows; i++) 
	 for (j=0; j < grid_cols; j++)
	 {
		 sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j]);
		 fputs(str,fp);
		 index++;
	 }

    fclose(fp);	
}

void readinput(float *vect, int grid_rows, int grid_cols, char *file) {
  	int i,j;
	FILE *fp;
	char str[STR_SIZE];
	float val;

	if( (fp  = fopen(file, "r" )) ==0 ) {
        fprintf(stderr, "The file was not opened\n");
        exit(1);
    }

	for (i=0; i <= grid_rows-1; i++) 
	 for (j=0; j <= grid_cols-1; j++)
	 {
		if (fgets(str, STR_SIZE, fp) == NULL) {
            fprintf(stderr, "Error reading file\n");
            exit(1);
        }
		if (feof(fp)) {
			fprintf(stderr, "not enough lines in file\n");
            exit(1);
        }

		if ((sscanf(str, "%f", &val) != 1)) {
			fprintf(stderr, "invalid file format\n");
            exit(1);
        }
		vect[i*grid_cols+j] = val;
	}

	fclose(fp);	
}

void hotspot(int iteration, float *power, float *temp_src, float *temp_dst, int grid_cols, int grid_rows, int border_cols, int border_rows, float Cap, float Rx, float Ry, float Rz, float step) {
	float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
	float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
	float temp_t[BLOCK_SIZE][BLOCK_SIZE];

	float step_div_Cap = step / Cap;
	float Rx_1 = 1.0f / Rx;
	float Ry_1 = 1.0f / Ry;
	float Rz_1 = 1.0f / Rz;

	int small_block_rows = BLOCK_SIZE - iteration * 2;
	int small_block_cols = BLOCK_SIZE - iteration * 2;

	int blockRows = (grid_rows + small_block_rows - 1) / small_block_rows;
	int blockCols = (grid_cols + small_block_cols - 1) / small_block_cols;

	// Parallelize over blocks and threads within blocks
	#pragma omp parallel for collapse(2) schedule(static)
	for (int by = 0; by < blockRows; by++) {
		for (int bx = 0; bx < blockCols; bx++) {
			// Each thread simulates a BLOCK_SIZE x BLOCK_SIZE block
			// We simulate the local threads tx, ty inside the block
			// Use nested loops for tx and ty
			float local_temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
			float local_power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
			float local_temp_t[BLOCK_SIZE][BLOCK_SIZE];

			int blkY = small_block_rows * by - border_rows;
			int blkX = small_block_cols * bx - border_cols;
			int blkYmax = blkY + BLOCK_SIZE - 1;
			int blkXmax = blkX + BLOCK_SIZE - 1;

			// Load data into local arrays
			for (int ty = 0; ty < BLOCK_SIZE; ty++) {
				for (int tx = 0; tx < BLOCK_SIZE; tx++) {
					int yidx = blkY + ty;
					int xidx = blkX + tx;
					if (IN_RANGE(yidx, 0, grid_rows - 1) && IN_RANGE(xidx, 0, grid_cols - 1)) {
						int index = yidx * grid_cols + xidx;
						local_temp_on_cuda[ty][tx] = temp_src[index];
						local_power_on_cuda[ty][tx] = power[index];
					} else {
						local_temp_on_cuda[ty][tx] = 0.0f;
						local_power_on_cuda[ty][tx] = 0.0f;
					}
				}
			}

			int validYmin = (blkY < 0) ? -blkY : 0;
			int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
			int validXmin = (blkX < 0) ? -blkX : 0;
			int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

			for (int i = 0; i < iteration; i++) {
				for (int ty = 0; ty < BLOCK_SIZE; ty++) {
					for (int tx = 0; tx < BLOCK_SIZE; tx++) {
						int N = ty - 1;
						int S = ty + 1;
						int W = tx - 1;
						int E = tx + 1;

						N = (N < validYmin) ? validYmin : N;
						S = (S > validYmax) ? validYmax : S;
						W = (W < validXmin) ? validXmin : W;
						E = (E > validXmax) ? validXmax : E;

						int tx_i = tx;
						int ty_i = ty;

						bool computed = false;
						if (IN_RANGE(tx_i, i + 1, BLOCK_SIZE - i - 2) &&
							IN_RANGE(ty_i, i + 1, BLOCK_SIZE - i - 2) &&
							IN_RANGE(tx_i, validXmin, validXmax) &&
							IN_RANGE(ty_i, validYmin, validYmax)) {
							computed = true;
							local_temp_t[ty][tx] = local_temp_on_cuda[ty][tx] + step_div_Cap * (local_power_on_cuda[ty][tx] +
								(local_temp_on_cuda[S][tx] + local_temp_on_cuda[N][tx] - 2.0f * local_temp_on_cuda[ty][tx]) * Ry_1 +
								(local_temp_on_cuda[ty][E] + local_temp_on_cuda[ty][W] - 2.0f * local_temp_on_cuda[ty][tx]) * Rx_1 +
								(amb_temp - local_temp_on_cuda[ty][tx]) * Rz_1);
						} else {
							local_temp_t[ty][tx] = local_temp_on_cuda[ty][tx];
						}
					}
				}
				if (i == iteration - 1)
					break;
				for (int ty = 0; ty < BLOCK_SIZE; ty++) {
					for (int tx = 0; tx < BLOCK_SIZE; tx++) {
						int tx_i = tx;
						int ty_i = ty;
						if (IN_RANGE(tx_i, i + 1, BLOCK_SIZE - i - 2) &&
							IN_RANGE(ty_i, i + 1, BLOCK_SIZE - i - 2) &&
							IN_RANGE(tx_i, validXmin, validXmax) &&
							IN_RANGE(ty_i, validYmin, validYmax)) {
							local_temp_on_cuda[ty][tx] = local_temp_t[ty][tx];
						}
					}
				}
			}

			// Write back results
			for (int ty = 0; ty < BLOCK_SIZE; ty++) {
				for (int tx = 0; tx < BLOCK_SIZE; tx++) {
					int yidx = blkY + ty;
					int xidx = blkX + tx;
					if (IN_RANGE(yidx, 0, grid_rows - 1) && IN_RANGE(xidx, 0, grid_cols - 1)) {
						int index = yidx * grid_cols + xidx;
						int i = iteration - 1;
						if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
							IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
							IN_RANGE(tx, validXmin, validXmax) &&
							IN_RANGE(ty, validYmin, validYmax)) {
							temp_dst[index] = local_temp_t[ty][tx];
						}
					}
				}
			}
		}
	}
}

int compute_tran_temp(int grid_cols, int grid_rows, int total_iterations, int num_iterations, int blockCols, int blockRows, int borderCols, int borderRows, float *TempCPU, float *PowerCPU) {
	float grid_height = chip_height / grid_rows;
	float grid_width = chip_width / grid_cols;

	float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
	float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
	float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
	float Rz = t_chip / (K_SI * grid_height * grid_width);

	float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
	float step = PRECISION / max_slope;

	float *temp_src = TempCPU;
	float *temp_dst = (float *)malloc(sizeof(float) * grid_rows * grid_cols);
	if (!temp_dst) {
		fprintf(stderr, "unable to allocate memory\n");
		exit(1);
	}

	int src = 0; // 0 means temp_src is current, 1 means temp_dst is current
	int dst = 1;

	for (int t = 0; t < total_iterations; t += num_iterations) {
		int iter = MIN(num_iterations, total_iterations - t);
		if (src == 0) {
			hotspot(iter, PowerCPU, temp_src, temp_dst, grid_cols, grid_rows, borderCols, borderRows, Cap, Rx, Ry, Rz, step);
		} else {
			hotspot(iter, PowerCPU, temp_dst, temp_src, grid_cols, grid_rows, borderCols, borderRows, Cap, Rx, Ry, Rz, step);
		}
		// Swap pointers
		int tmp = src;
		src = dst;
		dst = tmp;
	}

	if (src == 1) {
		// temp_dst has latest data, copy to temp_src
		memcpy(TempCPU, temp_dst, sizeof(float) * grid_rows * grid_cols);
		free(temp_dst);
	} else {
		free(temp_dst);
	}

	printf("Total: %d iterations completed\n", total_iterations);
	printf("Ending simulation\n");

	return 0;
}

void usage(int argc, char **argv) {
	fprintf(stderr, "Usage: %s <grid_rows/grid_cols> <pyramid_height> <sim_time> <temp_file> <power_file> <output_file> [-p platform_id] [-d device_id]\n", argv[0]);
	fprintf(stderr, "\t<grid_rows/grid_cols>  - number of rows/cols in the grid (positive integer)\n");
	fprintf(stderr, "\t<pyramid_height> - pyramid heigh(positive integer)\n");
	fprintf(stderr, "\t<sim_time>   - number of iterations\n");
	fprintf(stderr, "\t<temp_file>  - name of the file containing the initial temperature values of each cell\n");
	fprintf(stderr, "\t<power_file> - name of the file containing the dissipated power values of each cell\n");
	fprintf(stderr, "\t<output_file> - name of the output file\n");
	exit(1);
}

int main(int argc, char** argv) {
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

    int size;
    int grid_rows,grid_cols = 0;
    float *FilesavingTemp,*FilesavingPower; 
    char *tfile, *pfile, *ofile;

    int total_iterations = 60;
    int pyramid_height = 1; 

	if (argc < 7)
		usage(argc, argv);
	if((grid_rows = atoi(argv[1]))<=0||
	   (grid_cols = atoi(argv[1]))<=0||
       (pyramid_height = atoi(argv[2]))<=0||
       (total_iterations = atoi(argv[3]))<=0)
		usage(argc, argv);

	tfile=argv[4];
    pfile=argv[5];
    ofile=argv[6];
    size=grid_rows*grid_cols;

    int borderCols = (pyramid_height)*EXPAND_RATE/2;
    int borderRows = (pyramid_height)*EXPAND_RATE/2;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*EXPAND_RATE;
    int smallBlockRow = BLOCK_SIZE-(pyramid_height)*EXPAND_RATE;
    int blockCols = grid_cols/smallBlockCol+((grid_cols%smallBlockCol==0)?0:1);
    int blockRows = grid_rows/smallBlockRow+((grid_rows%smallBlockRow==0)?0:1);

    FilesavingTemp = (float *) malloc(size*sizeof(float));
    FilesavingPower = (float *) malloc(size*sizeof(float));

    if( !FilesavingPower || !FilesavingTemp) {
        fprintf(stderr, "unable to allocate memory\n");
        exit(1);
    }

    readinput(FilesavingTemp, grid_rows, grid_cols, tfile);
    readinput(FilesavingPower, grid_rows, grid_cols, pfile);

	int ret = compute_tran_temp(grid_cols, grid_rows, total_iterations, pyramid_height,
								blockCols, blockRows, borderCols, borderRows, FilesavingTemp, FilesavingPower);

	writeoutput(FilesavingTemp, grid_rows, grid_cols, ofile);

	free(FilesavingTemp);
	free(FilesavingPower);

	return 0;
}
